export function getOktaStateToken(data: string) {
  if (!data) throw new Error('Trying to get stateToken from empty data.');

  const oktaDataMatch = data.match(/oktaData = {.*/);
  if (oktaDataMatch == null)
    throw new Error('Could not find oktaData in input.');

  const oktaDataText = oktaDataMatch[0];

  const stateTokenMatch = oktaDataText.match(/\"stateToken\":\"[^\"]*\"/);
  if (stateTokenMatch == null)
    throw new Error('Could not find stateToken in oktaData.');

  const stateTokenText = stateTokenMatch[0];
  if (stateTokenText.indexOf(':') === -1)
    throw new Error(`Incorrectly formatted stateToken data: ${stateTokenText}`);

  const stateToken = stateTokenText
    .split(':')[1]
    .replace(/\"/g, '')
    .replace(/\\x/g, '%')
    .replace(/%2D/g, '-');

  return stateToken;
}
